import { createApp } from 'vue'
import App from './App.vue'
import router from './router'
import store from './store'

import ElementPlus from 'element-plus';                     //导入element-plus核心库
import locale from 'element-plus/lib/locale/lang/zh-cn';    //导入中文语言包，做本地化处理
import 'element-plus/dist/index.css';                       //导入CSS样式库

const app = createApp(App)
import * as ElIcons from '@element-plus/icons-vue'
for (const name in ElIcons) {
    app.component(name, ElIcons[name]);                     // 全局注册所有图标
}

app.use(store).use(router).use(ElementPlus, { locale }).mount('#app')